SELECT COUNT(DISTINCT S.PK_SIAPE) AS QUANTIDADE FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA CH ON CH.SIAPE = S.PK_SIAPE WHERE LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%farm%' AND LOWER(COALESCE(S.CONTRATO, '')) = 'efetivos' AND CH.ANO = 2023 AND CH.SEMESTRE = 1 AND LOWER(COALESCE(CH.SIGLA_CAMPUS, '')) = 'oes'